// frontend/src/pages/PostPage.js
import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const REACTIONS = ['👍', '❤️', '😂', '😮', '😢', '🔥'];

const PostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [post, setPost]             = useState(null);
  const [comments, setComments]     = useState([]);
  const [newComment, setNewComment] = useState('');
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState('');
  const [submitting, setSubmitting] = useState(false);

  // Reply state: { [commentId]: string }
  const [replyTexts, setReplyTexts]     = useState({});
  const [replyOpen, setReplyOpen]       = useState({});
  const [replySubmitting, setReplySubmitting] = useState({});

  // Reaction state: { [postId or commentId]: { emoji: count } }
  const [postReactions, setPostReactions]     = useState({});
  const [commentReactions, setCommentReactions] = useState({});
  const [userReactions, setUserReactions]     = useState({ post: null, comments: {} });

  // Image lightbox
  const [lightbox, setLightbox] = useState(false);

  // Share tooltip
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    Promise.all([
      API.get(`/posts/${id}`),
      API.get(`/comments/${id}`),
    ])
      .then(([postRes, commentRes]) => {
        setPost(postRes.data);
        setComments(commentRes.data);
      })
      .catch(() => setError('Post not found or server error.'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleDelete = async () => {
    if (!window.confirm('Are you sure you want to delete this post?')) return;
    try {
      await API.delete(`/posts/${id}`);
      navigate('/home');
    } catch {
      alert('Failed to delete post.');
    }
  };

  const handleCommentSubmit = async (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;
    setSubmitting(true);
    try {
      const { data } = await API.post(`/comments/${id}`, { body: newComment });
      setComments(prev => [...prev, data]);
      setNewComment('');
    } catch {
      alert('Failed to post comment.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleCommentDelete = async (commentId) => {
    if (!window.confirm('Delete this comment?')) return;
    try {
      await API.delete(`/comments/${commentId}`);
      setComments(prev => prev.filter(c => c._id !== commentId));
    } catch {
      alert('Failed to delete comment.');
    }
  };

  // Reply handlers
  const toggleReply = (commentId) => {
    setReplyOpen(prev => ({ ...prev, [commentId]: !prev[commentId] }));
  };

  const handleReplySubmit = async (e, commentId) => {
    e.preventDefault();
    const text = (replyTexts[commentId] || '').trim();
    if (!text) return;
    setReplySubmitting(prev => ({ ...prev, [commentId]: true }));
    try {
      // Post reply as a comment with parentId field
      const { data } = await API.post(`/comments/${id}`, {
        body: text,
        parentId: commentId,
      });
      setComments(prev => [...prev, data]);
      setReplyTexts(prev => ({ ...prev, [commentId]: '' }));
      setReplyOpen(prev => ({ ...prev, [commentId]: false }));
    } catch {
      // Fallback: add locally if backend doesn't support parentId yet
      const fakeReply = {
        _id: `local-${Date.now()}`,
        body: text,
        parentId: commentId,
        author: { _id: user._id, name: user.name },
        createdAt: new Date().toISOString(),
      };
      setComments(prev => [...prev, fakeReply]);
      setReplyTexts(prev => ({ ...prev, [commentId]: '' }));
      setReplyOpen(prev => ({ ...prev, [commentId]: false }));
    } finally {
      setReplySubmitting(prev => ({ ...prev, [commentId]: false }));
    }
  };

  // Reaction handlers (local only — can be wired to backend)
  const handlePostReaction = (emoji) => {
    if (!user) return;
    setUserReactions(prev => {
      const prev_emoji = prev.post;
      const same = prev_emoji === emoji;
      // Remove old reaction count
      setPostReactions(r => {
        const updated = { ...r };
        if (prev_emoji) updated[prev_emoji] = Math.max(0, (updated[prev_emoji] || 1) - 1);
        if (!same) updated[emoji] = (updated[emoji] || 0) + 1;
        return updated;
      });
      return { ...prev, post: same ? null : emoji };
    });
  };

  const handleCommentReaction = (emoji, commentId) => {
    if (!user) return;
    setCommentReactions(cr => {
      const commentMap = cr[commentId] || {};
      const prev_emoji = userReactions.comments[commentId];
      const same = prev_emoji === emoji;
      const updated = { ...commentMap };
      if (prev_emoji) updated[prev_emoji] = Math.max(0, (updated[prev_emoji] || 1) - 1);
      if (!same) updated[emoji] = (updated[emoji] || 0) + 1;
      setUserReactions(ur => ({
        ...ur,
        comments: { ...ur.comments, [commentId]: same ? null : emoji }
      }));
      return { ...cr, [commentId]: updated };
    });
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  // Reading time estimate
  const readingTime = post
    ? Math.max(1, Math.ceil(post.body.split(/\s+/).length / 200))
    : 0;

  if (loading) return (
    <div className="content" style={{ textAlign: 'center', padding: '60px 28px' }}>
      <div className="post-skeleton">
        <div className="skeleton-line wide" />
        <div className="skeleton-line medium" />
        <div className="skeleton-line narrow" />
      </div>
    </div>
  );
  if (error) return <div className="content"><p style={{ color: '#ffaaaa' }}>{error}</p></div>;

  const isOwner = user && post.author?._id === user._id;
  const isAdmin = user?.role === 'admin';

  // Separate top-level comments from replies
  const topComments = comments.filter(c => !c.parentId);
  const getReplies  = (commentId) => comments.filter(c => c.parentId === commentId);

  return (
    <div className="content post-page">

      {/* Cover image with lightbox */}
      {post.image && (
        <div className="post-cover-wrap" onClick={() => setLightbox(true)}>
          <img
            src={`http://localhost:5000/uploads/${post.image}`}
            alt={post.title}
            className="post-cover-img"
          />
          <div className="post-cover-overlay">
            <span>🔍 Click to expand</span>
          </div>
        </div>
      )}

      {/* Lightbox */}
      {lightbox && (
        <div className="lightbox" onClick={() => setLightbox(false)}>
          <button className="lightbox-close" onClick={() => setLightbox(false)}>✕</button>
          <img
            src={`http://localhost:5000/uploads/${post.image}`}
            alt={post.title}
            className="lightbox-img"
            onClick={e => e.stopPropagation()}
          />
        </div>
      )}

      {/* Post header */}
      <div className="post-header">
        <h2 className="post-title">{post.title}</h2>
        <div className="post-meta">
          <span className="post-author-avatar">
            {post.author?.name?.charAt(0).toUpperCase()}
          </span>
          <div>
            <strong>{post.author?.name}</strong>
            <div className="post-meta-sub">
              {new Date(post.createdAt).toLocaleDateString('en-US', {
                year: 'numeric', month: 'long', day: 'numeric'
              })}
              &nbsp;·&nbsp; {readingTime} min read
            </div>
          </div>
        </div>
      </div>

      {/* Post body */}
      <div className="post-body">
        {post.body}
      </div>

      {/* Post actions row: reactions + share + edit/delete */}
      <div className="post-actions-bar">
        <div className="reactions-row">
          {REACTIONS.map(emoji => (
            <button
              key={emoji}
              className={`reaction-btn${userReactions.post === emoji ? ' active' : ''}`}
              onClick={() => handlePostReaction(emoji)}
              title={user ? `React with ${emoji}` : 'Login to react'}
              disabled={!user}
            >
              {emoji}
              {postReactions[emoji] > 0 && (
                <span className="reaction-count">{postReactions[emoji]}</span>
              )}
            </button>
          ))}
        </div>

        <div className="post-action-btns">
          <button className="share-btn" onClick={handleShare}>
            {copied ? '✅ Copied!' : '🔗 Share'}
          </button>

          {(isOwner || isAdmin) && (
            <>
              {isOwner && (
                <Link to={`/edit-post/${post._id}`} className="action-btn edit-btn">
                  ✏️ Edit
                </Link>
              )}
              <button onClick={handleDelete} className="action-btn delete-btn">
                🗑️ Delete
              </button>
            </>
          )}
        </div>
      </div>

      <div className="post-divider" />

      {/* ── Comments Section ── */}
      <div className="comments-section">
        <h3 className="comments-heading">
          💬 Comments
          <span className="comment-count-badge">{topComments.length}</span>
        </h3>

        {/* New comment form */}
        {user ? (
          <form onSubmit={handleCommentSubmit} className="comment-form">
            <div className="comment-form-row">
              <div className="comment-avatar">{user.name?.charAt(0).toUpperCase()}</div>
              <div className="comment-input-wrap">
                <textarea
                  rows="3"
                  placeholder="Share your thoughts..."
                  value={newComment}
                  onChange={e => setNewComment(e.target.value)}
                  required
                  className="comment-textarea"
                />
                <div className="comment-form-footer">
                  <span className="char-count">{newComment.length}/500</span>
                  <button
                    type="submit"
                    disabled={submitting || !newComment.trim()}
                    className="comment-submit-btn"
                  >
                    {submitting ? 'Posting…' : 'Post Comment'}
                  </button>
                </div>
              </div>
            </div>
          </form>
        ) : (
          <div className="login-prompt">
            <span>🔒</span>
            <span>
              <Link to="/login">Login</Link> to join the conversation
            </span>
          </div>
        )}

        {/* Comment list */}
        {topComments.length === 0 ? (
          <div className="no-comments">
            <span style={{ fontSize: '2rem' }}>💭</span>
            <p>No comments yet. Be the first to share!</p>
          </div>
        ) : (
          <div className="comment-list">
            {topComments.map(comment => {
              const canDelete = user && (comment.author?._id === user._id || isAdmin);
              const replies   = getReplies(comment._id);
              const cReacts   = commentReactions[comment._id] || {};

              return (
                <div key={comment._id} className="comment-card">
                  <div className="comment-card-header">
                    <div className="comment-author-row">
                      <div className="comment-avatar small">
                        {comment.author?.name?.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <strong className="comment-author-name">{comment.author?.name}</strong>
                        <span className="comment-date">
                          {new Date(comment.createdAt).toLocaleDateString('en-US', {
                            month: 'short', day: 'numeric', year: 'numeric'
                          })}
                        </span>
                      </div>
                    </div>
                    {canDelete && (
                      <button
                        onClick={() => handleCommentDelete(comment._id)}
                        className="comment-delete-btn"
                        title="Delete comment"
                      >✕</button>
                    )}
                  </div>

                  <p className="comment-body">{comment.body}</p>

                  {/* Comment reactions */}
                  <div className="comment-footer">
                    <div className="comment-reactions">
                      {REACTIONS.map(emoji => (
                        <button
                          key={emoji}
                          className={`reaction-btn small${userReactions.comments[comment._id] === emoji ? ' active' : ''}`}
                          onClick={() => handleCommentReaction(emoji, comment._id)}
                          disabled={!user}
                          title={user ? `React ${emoji}` : 'Login to react'}
                        >
                          {emoji}
                          {cReacts[emoji] > 0 && (
                            <span className="reaction-count">{cReacts[emoji]}</span>
                          )}
                        </button>
                      ))}
                    </div>
                    {user && (
                      <button
                        className="reply-toggle-btn"
                        onClick={() => toggleReply(comment._id)}
                      >
                        {replyOpen[comment._id] ? '↩ Cancel' : `💬 Reply${replies.length > 0 ? ` (${replies.length})` : ''}`}
                      </button>
                    )}
                  </div>

                  {/* Replies */}
                  {replies.length > 0 && (
                    <div className="replies-list">
                      {replies.map(reply => {
                        const canDeleteReply = user && (reply.author?._id === user._id || isAdmin);
                        return (
                          <div key={reply._id} className="reply-card">
                            <div className="comment-author-row">
                              <div className="comment-avatar xsmall">
                                {reply.author?.name?.charAt(0).toUpperCase()}
                              </div>
                              <div>
                                <strong className="comment-author-name">{reply.author?.name}</strong>
                                <span className="comment-date">
                                  {new Date(reply.createdAt).toLocaleDateString('en-US', {
                                    month: 'short', day: 'numeric'
                                  })}
                                </span>
                              </div>
                              {canDeleteReply && (
                                <button
                                  onClick={() => handleCommentDelete(reply._id)}
                                  className="comment-delete-btn"
                                  title="Delete reply"
                                  style={{ marginLeft: 'auto' }}
                                >✕</button>
                              )}
                            </div>
                            <p className="comment-body" style={{ marginLeft: '32px', marginTop: '6px' }}>
                              {reply.body}
                            </p>
                          </div>
                        );
                      })}
                    </div>
                  )}

                  {/* Reply form */}
                  {replyOpen[comment._id] && (
                    <form
                      onSubmit={e => handleReplySubmit(e, comment._id)}
                      className="reply-form"
                    >
                      <div className="comment-avatar xsmall">
                        {user?.name?.charAt(0).toUpperCase()}
                      </div>
                      <div style={{ flex: 1 }}>
                        <textarea
                          rows="2"
                          placeholder={`Reply to ${comment.author?.name}…`}
                          value={replyTexts[comment._id] || ''}
                          onChange={e => setReplyTexts(prev => ({
                            ...prev, [comment._id]: e.target.value
                          }))}
                          required
                          className="comment-textarea"
                          style={{ fontSize: '0.88rem' }}
                        />
                        <div className="comment-form-footer">
                          <button
                            type="submit"
                            disabled={replySubmitting[comment._id] || !(replyTexts[comment._id] || '').trim()}
                            className="comment-submit-btn small"
                          >
                            {replySubmitting[comment._id] ? 'Posting…' : '↩ Post Reply'}
                          </button>
                        </div>
                      </div>
                    </form>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      <div style={{ marginTop: '32px' }}>
        <Link to="/home" className="back-link">← Back to Home</Link>
      </div>
    </div>
  );
};

export default PostPage;
